import unittest
from phone_parser import parse_phone

class TestPhoneParser(unittest.TestCase):
    def test_basic_extract(self):
        text = 'Call (123) 456-7890 for details.'
        self.assertEqual(parse_phone(text), ['1234567890'])
    def test_missing_format(self):
        text = '123-456-7890 is wrong.' # Matches should be strict
        self.assertEqual(parse_phone(text), [])

if __name__ == '__main__':
    unittest.main()
